import json
import glob
import re

# Let's write a function to read orders for a store on a given day
def read_order(day, store_id):
    # day is like 1, 2, ...
    # Find file in raw_orders like day_{day:03d}_{store_id}_*
    pattern = f"raw_orders/day_{day:03d}_{store_id}_*"
    files = glob.glob(pattern)
    if not files:
        return None
    file_path = files[0]
    items = {}
    if file_path.endswith('.json'):
        with open(file_path, 'r') as f:
            data = json.load(f)
            for item in data.get('items', []):
                items[item['prod_id']] = item.get('qty') or item.get('ordered_qty') or item.get('delivered_qty')
    elif file_path.endswith('.csv'):
        # PRODUCT;QUANTITY
        with open(file_path, 'r') as f:
            lines = f.readlines()
            for line in lines[1:]:
                parts = line.strip().split(';')
                if len(parts) == 2:
                    items[parts[0]] = int(parts[1])
    elif file_path.endswith('.txt'):
        with open(file_path, 'r') as f:
            content = f.read()
        if "RECEIVER" in content:
            # RECEIVER: S_2 | ORDER_PRODUCT: P_1 | ORDER_QTY: 55
            for line in content.strip().split('\n'):
                m = re.search(r'ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', line)
                if m:
                    items[m.group(1)] = int(m.group(2))
        else:
            # Order from Day_1. Please deliver 81 units of product P_1. Regards, Store S_1.
            for line in content.strip().split('\n'):
                m = re.search(r'deliver\s*(\d+)\s*units\s*of\s*product\s*(P_\d+)', line)
                if m:
                    items[m.group(2)] = int(m.group(1))
    return items

# Let's read S_10's order on Day 1
ord_10 = read_order(1, "S_10")
print("S_10 order on Day 1:", ord_10)
if ord_10:
    print("Total ordered qty S_10:", sum(ord_10.values()))

# Let's read the store receipt for S_10 on Day 1
receipt_file = "raw_wholesaler_store_receipts/day_001_S_10_receipt.txt"
with open(receipt_file, 'r') as f:
    print("Receipt S_10:", f.read())

