import os
import glob
import re
import json

def get_orders_and_receipts():
    underfulfilled_count = 0
    total_checked = 0

    # We will check first 30 days
    for day in range(1, 31):
        # Read store receipts for this day
        receipt_files = glob.glob(f"raw_wholesaler_store_receipts/day_{day:03d}_S_*_receipt.txt")
        for rf in receipt_files:
            # Extract store_id
            m = re.search(r'S_(\d+)', rf)
            if not m:
                continue
            store_id = f"S_{m.group(1)}"

            # Read receipt TOTAL_DELIVERED_UNITS
            with open(rf, 'r') as f:
                content = f.read()
            m_del = re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content)
            if not m_del:
                continue
            delivered = int(m_del.group(1))

            # Read order total
            # Find file in raw_orders like day_{day:03d}_{store_id}_*
            pattern = f"raw_orders/day_{day:03d}_{store_id}_*"
            files = glob.glob(pattern)
            if not files:
                # No order file means 0 ordered
                ordered = 0
            else:
                file_path = files[0]
                items = {}
                if file_path.endswith('.json'):
                    with open(file_path, 'r') as f:
                        data = json.load(f)
                        for item in data.get('items', []):
                            items[item['prod_id']] = item.get('qty') or item.get('ordered_qty') or item.get('delivered_qty')
                elif file_path.endswith('.csv'):
                    with open(file_path, 'r') as f:
                        lines = f.readlines()
                        for line in lines[1:]:
                            parts = line.strip().split(';')
                            if len(parts) == 2:
                                items[parts[0]] = int(parts[1])
                elif file_path.endswith('.txt'):
                    with open(file_path, 'r') as f:
                        content_txt = f.read()
                    if "RECEIVER" in content_txt:
                        for line in content_txt.strip().split('\n'):
                            m_p = re.search(r'ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', line)
                            if m_p:
                                items[m_p.group(1)] = int(m_p.group(2))
                    else:
                        for line in content_txt.strip().split('\n'):
                            m_p = re.search(r'deliver\s*(\d+)\s*units\s*of\s*product\s*(P_\d+)', line)
                            if m_p:
                                items[m_p.group(2)] = int(m_p.group(1))
                ordered = sum(items.values())

            total_checked += 1
            if delivered < ordered:
                underfulfilled_count += 1
                print(f"Day {day}, {store_id}: Ordered {ordered}, Delivered {delivered} (Underfulfilled by {ordered - delivered})")
                # Print the item order
                print("Ordered items:", items)

    print(f"Total checked: {total_checked}, underfulfilled: {underfulfilled_count}")

get_orders_and_receipts()

