import os
import glob
import re
import json
import pandas as pd

def parse_supplier_receipts():
    # Day -> Supplier_ID -> {Product_ID -> Qty}
    supplier_data = {}
    pattern = "raw_supplier_receipts/day_*"
    files = glob.glob(pattern)
    print(f"Parsing {len(files)} supplier receipts...")

    # regex for day and supplier id
    # format: day_001_PR_1_table-csv.csv, etc.
    file_re = re.compile(r'day_(\d+)_PR_(\d+)_')

    for f_path in files:
        f_name = os.path.basename(f_path)
        m = file_re.search(f_name)
        if not m:
            continue
        day = int(m.group(1))
        supplier_id = f"PR_{m.group(2)}"

        if day not in supplier_data:
            supplier_data[day] = {}
        if supplier_id not in supplier_data[day]:
            supplier_data[day][supplier_id] = {}

        items = {}
        if f_path.endswith('.json'):
            with open(f_path, 'r') as f:
                data = json.load(f)
                for item in data.get('items', []):
                    qty = item.get('qty') or item.get('delivered_qty') or item.get('delivered')
                    items[item['prod_id']] = int(qty)
        elif f_path.endswith('.csv'):
            with open(f_path, 'r') as f:
                lines = f.readlines()
                for line in lines[1:]:
                    parts = line.strip().split(';')
                    if len(parts) == 2:
                        items[parts[0]] = int(parts[1])
        elif f_path.endswith('.txt'):
            with open(f_path, 'r') as f:
                content = f.read()
            if "SUPPLIER" in content:
                # PRODUCT: P_1 | DELIVERED_QTY: 14
                for line in content.strip().split('\n'):
                    m_p = re.search(r'PRODUCT:\s*(P_\d+)\s*\|\s*DELIVERED_QTY:\s*(\d+)', line)
                    if m_p:
                        items[m_p.group(1)] = int(m_p.group(2))
            else:
                # Supplier PR_10 delivered 12 units of product P_1 to the wholesaler on Day_1.
                for line in content.strip().split('\n'):
                    m_p = re.search(r'delivered\s*(\d+)\s*units\s*of\s*product\s*(P_\d+)', line)
                    if m_p:
                        items[m_p.group(2)] = int(m_p.group(1))

        supplier_data[day][supplier_id] = items
    return supplier_data

def parse_wholesaler_receipts():
    # Day -> list of (seq, supplier_id)
    wholesaler_data = {}
    pattern = "raw_wholesaler_receipts/day_*"
    files = glob.glob(pattern)
    print(f"Parsing {len(files)} wholesaler receipts...")

    file_re = re.compile(r'day_(\d+)_PR_(\d+)_receipt.txt')
    for f_path in files:
        f_name = os.path.basename(f_path)
        m = file_re.search(f_name)
        if not m:
            continue
        day = int(m.group(1))
        supplier_id = f"PR_{m.group(2)}"

        with open(f_path, 'r') as f:
            content = f.read()
        seq = int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content).group(1))

        if day not in wholesaler_data:
            wholesaler_data[day] = []
        wholesaler_data[day].append((seq, supplier_id))

    for day in wholesaler_data:
        wholesaler_data[day].sort(key=lambda x: x[0])
    return wholesaler_data

def parse_wholesaler_store_receipts():
    # Day -> list of (seq, store_id, total_delivered_units)
    store_receipts = {}
    pattern = "raw_wholesaler_store_receipts/day_*"
    files = glob.glob(pattern)
    print(f"Parsing {len(files)} wholesaler store receipts...")

    file_re = re.compile(r'day_(\d+)_S_(\d+)_receipt.txt')
    for f_path in files:
        f_name = os.path.basename(f_path)
        m = file_re.search(f_name)
        if not m:
            continue
        day = int(m.group(1))
        store_id = f"S_{m.group(2)}"

        with open(f_path, 'r') as f:
            content = f.read()
        seq = int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content).group(1))
        tot = int(re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', content).group(1))

        if day not in store_receipts:
            store_receipts[day] = []
        store_receipts[day].append((seq, store_id, tot))

    for day in store_receipts:
        store_receipts[day].sort(key=lambda x: x[0])
    return store_receipts

def parse_store_orders():
    # Day -> Store_ID -> {Product_ID -> Qty}
    store_orders = {}
    pattern = "raw_orders/day_*"
    files = glob.glob(pattern)
    print(f"Parsing {len(files)} store orders...")

    file_re = re.compile(r'day_(\d+)_S_(\d+)_')
    for f_path in files:
        f_name = os.path.basename(f_path)
        m = file_re.search(f_name)
        if not m:
            continue
        day = int(m.group(1))
        store_id = f"S_{m.group(2)}"

        if day not in store_orders:
            store_orders[day] = {}
        if store_id not in store_orders[day]:
            store_orders[day][store_id] = {}

        items = {}
        if f_path.endswith('.json'):
            with open(f_path, 'r') as f:
                data = json.load(f)
                for item in data.get('items', []):
                    qty = item.get('qty') or item.get('ordered_qty') or item.get('delivered_qty')
                    items[item['prod_id']] = int(qty)
        elif f_path.endswith('.csv'):
            with open(f_path, 'r') as f:
                lines = f.readlines()
                for line in lines[1:]:
                    parts = line.strip().split(';')
                    if len(parts) == 2:
                        items[parts[0]] = int(parts[1])
        elif f_path.endswith('.txt'):
            with open(f_path, 'r') as f:
                content = f.read()
            if "RECEIVER" in content:
                for line in content.strip().split('\n'):
                    m_p = re.search(r'ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', line)
                    if m_p:
                        items[m_p.group(1)] = int(m_p.group(2))
            else:
                for line in content.strip().split('\n'):
                    m_p = re.search(r'deliver\s*(\d+)\s*units\s*of\s*product\s*(P_\d+)', line)
                    if m_p:
                        items[m_p.group(2)] = int(m_p.group(1))

        store_orders[day][store_id] = items
    return store_orders

if __name__ == '__main__':
    supp = parse_supplier_receipts()
    whole_supp = parse_wholesaler_receipts()
    whole_store = parse_wholesaler_store_receipts()
    orders = parse_store_orders()

    print("\nParsing summary:")
    print("Days in supplier receipts:", len(supp))
    print("Days in wholesaler supplier receipts:", len(whole_supp))
    print("Days in wholesaler store receipts:", len(whole_store))
    print("Days in store orders:", len(orders))

