    files = glob.glob(pattern)
    print(f"Parsing {len(files)} store orders...")

    file_re = re.compile(r'day_(\d+)_S_(\d+)_')
    for f_path in files:
        f_name = os.path.basename(f_path)
        m = file_re.search(f_name)
        if not m:
            continue
        day = int(m.group(1))
        store_id = f"S_{m.group(2)}"

        if day not in store_orders:
            store_orders[day] = {}
        if store_id not in store_orders[day]:
            store_orders[day][store_id] = {}

        items = {}
        if f_path.endswith('.json'):
            with open(f_path, 'r') as f:
                data = json.load(f)
                for item in data.get('items', []):
                    qty = item.get('qty') or item.get('ordered_qty') or item.get('delivered_qty')
                    items[item['prod_id']] = int(qty)
        elif f_path.endswith('.csv'):
            with open(f_path, 'r') as f:
                lines = f.readlines()
                for line in lines[1:]:
                    parts = line.strip().split(';')
                    if len(parts) == 2:
                        items[parts[0]] = int(parts[1])
        elif f_path.endswith('.txt'):
            with open(f_path, 'r') as f:
                content = f.read()
            if "RECEIVER" in content:
                for line in content.strip().split('\n'):
                    m_p = re.search(r'ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', line)
                    if m_p:
                        items[m_p.group(1)] = int(m_p.group(2))
            else:
                for line in content.strip().split('\n'):
                    m_p = re.search(r'deliver\s*(\d+)\s*units\s*of\s*product\s*(P_\d+)', line)
                    if m_p:
                        items[m_p.group(2)] = int(m_p.group(1))

        store_orders[day][store_id] = items
    return store_orders

if __name__ == '__main__':
    supp = parse_supplier_receipts()
    whole_supp = parse_wholesaler_receipts()
    whole_store = parse_wholesaler_store_receipts()
    orders = parse_store_orders()

    print("\nParsing summary:")
    print("Days in supplier receipts:", len(supp))
    print("Days in wholesaler supplier receipts:", len(whole_supp))
    print("Days in wholesaler store receipts:", len(whole_store))
    print("Days in store orders:", len(orders))

